// Timestamp-Based Concurrency Control

// Data structures
data_item:
 value
 Read_Timestamp (RTS)
 Write_Timestamp (WTS)

// Read Operation
FUNCTION READ(T, X)
 IF T.timestamp >= X.WTS
 // Allow read
 READ_VALUE = X.value
 X.RTS = MAX(X.RTS, T.timestamp)
 RETURN READ_VALUE
 ELSE
 // Reject - younger transaction wrote X
 ABORT_TRANSACTION(T)
 END IF

// Write Operation
FUNCTION WRITE(T, X, new_value)
 IF T.timestamp >= X.RTS AND T.timestamp >= X.WTS
 // Allow write
 X.value = new_value
 X.WTS = T.timestamp
 ELSE IF T.timestamp < X.WTS
 // Thomas Write Rule: ignore obsolete write
 CONTINUE
 ELSE
 // Reject - conflict with younger read
 ABORT_TRANSACTION(T)
 END IF

// Wait-Die Deadlock Prevention Scheme

FUNCTION REQUEST_LOCK(transaction T, resource R)
 IF R.holder == NULL
 GRANT_LOCK(T, R)
 ELSE
 holder_H = R.holder

 IF T.timestamp < H.timestamp
 // T is older than holder - wait
 ADD_TO_WAIT_QUEUE(T, R)
 TRANSACTION_WAIT()
 ELSE
 // T is younger than holder - die (abort)
 ABORT_TRANSACTION(T)
 RESTART_WITH_NEW_TIMESTAMP(T)
 END IF
 END IF

// Key properties:
// - Only older transactions wait
// - Younger transactions always abort
// - No circular wait possible
// - Results in more aborts for older transactions
